// HTML nümunəsi:
/*
<div id="productCard" class="item" data-product-id="123" data-stock="5">Kamera - $200</div>
<button class="update-btn">Yenilə</button>
*/

// 1. Atribut oxuma
const productCard = document.getElementById("productCard");
console.log(productCard.getAttribute("class")); // "item"
console.log(productCard.getAttribute("data-product-id")); // "123"

// 2. Atribut dəyişdirmə
productCard.setAttribute("data-stock", "10");
// nəticə: <div id="productCard" class="item" data-product-id="123" data-stock="10">

productCard.setAttribute("style", "color: red;");
// nəticə: <div id="productCard" class="item" data-product-id="123" data-stock="10" style="color: red;">

// 3. Atribut silmə
productCard.removeAttribute("style");
// nəticə: style atributu silinir

// 4. Atributun mövcudluğunu yoxlama
console.log(productCard.hasAttribute("data-stock")); // true
console.log(productCard.hasAttribute("title")); // false

// 5. Data atributları ilə işləmə
const stock = productCard.dataset.stock;
console.log(stock); // "10"

productCard.dataset.price = "250";
// nəticə: <div id="productCard" class="item" data-product-id="123" data-stock="10" data-price="250">

// 6. Hadisə ilə atribut yeniləmə
const updateButton = document.querySelector(".update-btn");
updateButton.addEventListener("click", () => {
  productCard.setAttribute("data-stock", "15");
  productCard.textContent = "Kamera - $200 (Stok: 15)";
});
// nəticə: Düyməyə klikləyəndə stok yenilənir

// Təhlükə nümunəsi: Təhlükəsiz olmayan atribut dəyişdirmə
const userInput = "<script>alert('Hücum!');</script>";
productCard.setAttribute("title", userInput);
// Təhlükə: Zərərli kod potensial olaraq işləyə bilər

// Təhlükəsiz alternativ
const safeInput = "Məhsul haqqında məlumat";
productCard.setAttribute("title", safeInput);
// nəticə: <div id="productCard" title="Məhsul haqqında məlumat">

// Dinamik atribut əlavə etmə
const addDiscount = () => {
  productCard.dataset.discount = "20%";
  productCard.textContent = "Kamera - $200 (Endirim: 20%)";
};
updateButton.addEventListener("click", addDiscount);
// nəticə: Düyməyə klikləyəndə data-discount əlavə olunur

// Atribut yoxlaması ilə şərt
const checkStock = () => {
  if (productCard.hasAttribute("data-stock")) {
    console.log(`Stok: ${productCard.dataset.stock}`);
  } else {
    console.log("Stok məlumatı yoxdur!");
  }
};
checkStock();
// nəticə: Stok: 10 (və ya "Stok məlumatı yoxdur!")

