// HTML example:
/*
<div id="productCard" class="item" data-product-id="123" data-stock="5">Camera - $200</div>
<button class="update-btn">Update</button>
*/

// 1. Reading attributes
const productCard = document.getElementById("productCard");
console.log(productCard.getAttribute("class")); // "item"
console.log(productCard.getAttribute("data-product-id")); // "123"

// 2. Modifying attributes
productCard.setAttribute("data-stock", "10");
// Output: <div id="productCard" class="item" data-product-id="123" data-stock="10">

productCard.setAttribute("style", "color: red;");
// Output: <div id="productCard" class="item" data-product-id="123" data-stock="10" style="color: red;">

// 3. Removing attributes
productCard.removeAttribute("style");
// Output: style attribute is removed

// 4. Checking attribute existence
console.log(productCard.hasAttribute("data-stock")); // true
console.log(productCard.hasAttribute("title")); // false

// 5. Working with data attributes
const stock = productCard.dataset.stock;
console.log(stock); // "10"

productCard.dataset.price = "250";
// Output: <div id="productCard" class="item" data-product-id="123" data-stock="10" data-price="250">

// 6. Updating attributes with events
const updateButton = document.querySelector(".update-btn");
updateButton.addEventListener("click", () => {
  productCard.setAttribute("data-stock", "15");
  productCard.textContent = "Camera - $200 (Stock: 15)";
});
// Output: Clicking the button updates the stock

// Danger example: Unsafe attribute modification
const userInput = "<script>alert('Attack!');</script>";
productCard.setAttribute("title", userInput);
// Danger: Malicious code could potentially run

// Safe alternative
const safeInput = "Product information";
productCard.setAttribute("title", safeInput);
// Output: <div id="productCard" title="Product information">

// Dynamic attribute addition
const addDiscount = () => {
  productCard.dataset.discount = "20%";
  productCard.textContent = "Camera - $200 (Discount: 20%)";
};
updateButton.addEventListener("click", addDiscount);
// Output: Clicking the button adds data-discount

// Conditional attribute check
const checkStock = () => {
  if (productCard.hasAttribute("data-stock")) {
    console.log(`Stock: ${productCard.dataset.stock}`);
  } else {
    console.log("No stock information!");
  }
};
checkStock();
// Output: Stock: 10 (or "No stock information!")

