// Пример HTML:
/*
<div id="productCard" class="item" data-product-id="123" data-stock="5">Камера - $200</div>
<button class="update-btn">Обновить</button>
*/

// 1. Чтение атрибутов
const productCard = document.getElementById("productCard");
console.log(productCard.getAttribute("class")); // "item"
console.log(productCard.getAttribute("data-product-id")); // "123"

// 2. Изменение атрибутов
productCard.setAttribute("data-stock", "10");
// Вывод: <div id="productCard" class="item" data-product-id="123" data-stock="10">

productCard.setAttribute("style", "color: red;");
// Вывод: <div id="productCard" class="item" data-product-id="123" data-stock="10" style="color: red;">

// 3. Удаление атрибутов
productCard.removeAttribute("style");
// Вывод: атрибут style удалён

// 4. Проверка наличия атрибута
console.log(productCard.hasAttribute("data-stock")); // true
console.log(productCard.hasAttribute("title")); // false

// 5. Работа с data-атрибутами
const stock = productCard.dataset.stock;
console.log(stock); // "10"

productCard.dataset.price = "250";
// Вывод: <div id="productCard" class="item" data-product-id="123" data-stock="10" data-price="250">

// 6. Обновление атрибутов с событиями
const updateButton = document.querySelector(".update-btn");
updateButton.addEventListener("click", () => {
  productCard.setAttribute("data-stock", "15");
  productCard.textContent = "Камера - $200 (Склад: 15)";
});
// Вывод: При клике на кнопку обновляется склад

// Пример опасности: Небезопасное изменение атрибута
const userInput = "<script>alert('Атака!');</script>";
productCard.setAttribute("title", userInput);
// Опасность: Вредоносный код может потенциально выполниться

// Безопасная альтернатива
const safeInput = "Информация о товаре";
productCard.setAttribute("title", safeInput);
// Вывод: <div id="productCard" title="Информация о товаре">

// Динамическое добавление атрибута
const addDiscount = () => {
  productCard.dataset.discount = "20%";
  productCard.textContent = "Камера - $200 (Скидка: 20%)";
};
updateButton.addEventListener("click", addDiscount);
// Вывод: При клике на кнопку добавляется data-discount

// Проверка атрибута с условием
const checkStock = () => {
  if (productCard.hasAttribute("data-stock")) {
    console.log(`Склад: ${productCard.dataset.stock}`);
  } else {
    console.log("Нет информации о складе!");
  }
};
checkStock();
// Вывод: Склад: 10 (или "Нет информации о складе!")

